<?php namespace App\Services; use App\Models\SiteSetting; use Illuminate\Support\Facades\Cache; class SettingsService {     private string $cacheKey;     private int $cacheTtl;     public function __construct() {         $this->cacheKey = config("hopn.settings_cache_key", "hopn_site_settings");         $this->cacheTtl = config("hopn.settings_cache_ttl", 3600);     }     public function all(): array {         return Cache::remember($this->cacheKey, $this->cacheTtl, function () {             $row = SiteSetting::first();             return $row ? $row->toArray() : [];         });     }     public function get(string $key, mixed $default = null): mixed {         return $this->all()[$key] ?? $default;     }     public function set(string $key, mixed $value): void {         $row = SiteSetting::firstOrNew([]);         $row->$key = $value;         $row->save();         $this->clearCache();     }     public function bulkSet(array $settings): void {         $row = SiteSetting::firstOrNew([]);         foreach ($settings as $key => $value) { $row->$key = $value; }         $row->save();         $this->clearCache();     }     public function clearCache(): void {         Cache::forget($this->cacheKey);     } }